var messages = [];

for (var i = 0; i < msg.payload.length; i++) {
    var ligne = msg.payload[i];

    // Le "Z" force Node-RED à appliquer le bon fuseau horaire (+2h pour la France)
    var temps = new Date(ligne.date + "Z").getTime();

    messages.push({
        topic: ligne.culture, 
        payload: ligne.temp_air,
        timestamp: temps 
    });
}

return [messages];

// 1. Récupération du profil des FRAISES
var fraises = {
    meteo: flow.get("fraise_meteo") || "En attente des capteurs...",
    seuils: {
        humidite_sol_min: flow.get("fraise_seuil_hum") || 40,
        lumiere_max: flow.get("fraise_seuil_lux") || 800
    },
    alerte_actuelle: flow.get("fraise_alerte") || "Tout va bien"
};

// 2. Récupération du profil des TOMATES
var tomates = {
    meteo: flow.get("tomate_meteo") || "En attente des capteurs...",
    seuils: {
        humidite_sol_min: flow.get("tomate_seuil_hum") || 30,
        lumiere_max: flow.get("tomate_seuil_lux") || 800
    },
    alerte_actuelle: flow.get("tomate_alerte") || "Tout va bien"
};

// 3. Construction du JSON final (Le rapport complet)
msg.payload = {
    systeme: {
        statut: "En ligne",
        rythme_actualisation_minutes: flow.get("frequence_minutes") || 5
    },
    cultures: {
        zone_1_fraises: fraises,
        zone_2_tomates: tomates
    }
};

return msg;

// Les fraises préfèrent la douceur (15 à 25°C)
msg.payload = {
    air: {
        temp: Math.round((Math.random() * 10 + 15) * 10) / 10,
        hum: Math.round(Math.random() * 30 + 50) // 50 à 80%
    },
    sol: {
        temp: Math.round((Math.random() * 20 + 15) * 10) / 10,
        hum: Math.round(Math.random() * 40 + 50) // 50 à 80%
    },
    sol_moyenne: {
        hum: Math.round(Math.random() * 40 + 40) // 40 à 80%
    },
    lumiere: Math.round(Math.random() * 600 + 200),
    erreurs: false
};

// 1. On identifie la culture pour la base de données
msg.culture = "Fraises";

// 2. On sauvegarde cette météo sur le post-it spécifique aux FRAISES
flow.set("fraise_meteo", msg.payload);

return msg;

// Les tomates aiment la chaleur (22 à 26°C)
msg.payload = {
    air: {
        temp: Math.round((Math.random() * 10 + 18) * 10) / 10,
        hum: Math.round(Math.random() * 15 + 60) // 60 à 75%
    },
    sol: {
        temp: Math.round((Math.random() * 5 + 18) * 10) / 10,
        hum: Math.round(Math.random() * 20 + 60) // 50 à 80%
    },
    sol_moyenne: {
        hum: Math.round(Math.random() * 10 + 65) // 40 à 80%
    },
    lumiere: Math.round(Math.random() * 800 + 400),
    erreurs: false
};

// 1. On identifie la culture pour la base de données
msg.culture = "Tomates";

// 2. On sauvegarde cette météo sur le post-it spécifique aux TOMATES
flow.set("tomate_meteo", msg.payload);

return msg;

// 1. On lit les curseurs de la page web (avec des valeurs par défaut au cas où)
var seuilHum = flow.get("fraise_seuil_hum") || 40;
var seuilLux = flow.get("fraise_seuil_lux") || 800;

var alerte = ""; // Au départ, tout va bien, le message est vide
var arrosage = false;
var fermer_volets = false;

// 2. On compare la météo avec les seuils
// Test de l'humidité
if (msg.payload.sol_moyenne.hum <= seuilHum) {
    alerte += "💧 Sol Fraises trop sec (" + msg.payload.sol_moyenne.hum + "%). ";
    arrosage = true;
}

// Test de la lumière
if (msg.payload.lumiere >= seuilLux) {
    alerte += "☀️ Trop de soleil sur les Fraises (" + msg.payload.lumiere + " Lux). ";
    fermer_volets = true;
}

// 3. On colle le message d'alerte sur un post-it pour que le Tab 1 puisse le lire
flow.set("fraise_alerte", alerte);

// 4. On prépare les ordres pour les machines
msg.ordres = {
    pompe: arrosage,
    volets: fermer_volets ? "descendre" : "monter"
};

return msg;

// Le vigile lit les post-its des deux serres
var alerteF = flow.get("fraise_alerte") || "";
var alerteT = flow.get("tomate_alerte") || ""; // Même si la tomate n'existe pas encore, ça ne plantera pas

// S'il y a du texte dans l'une des alertes
if (alerteF !== "" || alerteT !== "") {
    msg.couleur = "#e74c3c"; // Rouge Pompier
    msg.titre = "⚠️ SYSTÈME EN ALERTE";
    msg.detail = alerteF + alerteT; // On affiche les textes
} 
// Si les deux alertes sont vides (tout va bien)
else {
    msg.couleur = "#2ecc71"; // Vert Validé
    msg.titre = "✅ SYSTÈME OPTIMAL";
    msg.detail = "Aucune anomalie détectée sur les cultures.";
}

return msg;

// 1. On lit la fréquence choisie par l'utilisateur (par défaut 5 minutes)
var frequenceMin = flow.get("frequence_minutes") ||  5;

// 2. On lit l'heure du dernier relevé (0 si c'est le tout premier)
var dernierReleve = flow.get("heure_dernier_releve") ||  0;

// 3. On regarde l'heure exacte qu'il est maintenant (en millisecondes)
var maintenant = new Date().getTime();

// 4. On calcule combien de temps on doit attendre (minutes -> millisecondes)
var tempsAttente = frequenceMin * 60 * 1000;

// 5. Si le temps écoulé est plus grand que le temps d'attente...
if (maintenant - dernierReleve >= tempsAttente) {
    // ... On met à jour l'heure du dernier relevé !
    flow.set("heure_dernier_releve", maintenant);

    // Et on donne le feu vert pour déclencher les capteurs
    return msg; 
}

// Sinon, on ne fait rien (on attend la prochaine seconde)
return null;

// 1. On lit les curseurs de la page web (avec des valeurs par défaut au cas où)
var seuilHum = flow.get("tomate_seuil_hum") || 40;
var seuilLux = flow.get("tomate_seuil_lux") || 800;

var alerte = ""; // Au départ, tout va bien, le message est vide
var arrosage = false;
var fermer_volets = false;

// 2. On compare la météo avec les seuils
// Test de l'humidité
if (msg.payload.sol_moyenne.hum <= seuilHum) {
    alerte += "💧 Sol Tomates trop sec (" + msg.payload.sol_moyenne.hum + "%). ";
    arrosage = true;
}

// Test de la lumière
if (msg.payload.lumiere >= seuilLux) {
    alerte += "☀️ Trop de soleil sur les Tomates (" + msg.payload.lumiere + " Lux). ";
    fermer_volets = true;
}

// 3. On colle le message d'alerte sur un post-it pour que le Tab 1 puisse le lire
flow.set("tomate_alerte", alerte);

// 4. On prépare les ordres pour les machines
msg.ordres = {
    pompe: arrosage,
    volets: fermer_volets ? "descendre" : "monter"
};

return msg;
